Method.Source:
    public void modified()
    {
        UBSVendBankAccountAccountIdOrigField UBSVendBankAccountAccountIdOrigField;

        FormDataObject  formDataObject          = any2Object(this) as FormDataObject;
        FormDataSource  formDataSource          = formDataObject.datasource();
        VendBankAccount vendBankAccountLoc      = formDataSource.cursor();
        VendBankAccount vendBankAccountLocOld   = vendBankAccountLoc.orig();
        int             vendBankAccountCount    = VendBankAccount::vendBankAccountPerVendorCount(vendBankAccountLoc.VendAccount);

        if(!vendBankAccountLocOld.AccountID && !vendBankAccountCount)
        {
            delete_from UBSVendBankAccountAccountIdOrigField
                where  UBSVendBankAccountAccountIdOrigField.AccountID == vendBankAccountLocOld.AccountID;

            ttsbegin;
            UBSVendBankAccountAccountIdOrigField.AccountID  = vendBankAccountLoc.AccountId;
            UBSVendBankAccountAccountIdOrigField.insert();
            ttscommit;
        }

        next modified();
    }
